const filteredData = json.filter(item => item.codigo && item.codigo.includes("CRED")).map(item => {
    return {
        "id": item.id,
        "nome": item.nome,
        "codigo": item.codigo
    };
});

// Ordenar pelo número após "CRED-"
filteredData.sort((a, b) => {
    const aNumber = parseInt(a.codigo.split('-')[1]);
    const bNumber = parseInt(b.codigo.split('-')[1]);
    return aNumber - bNumber;
});

const formattedData = { dados: filteredData };

console.log(JSON.stringify(formattedData, null, 2));
